&lt;ul&gt;
	&lt;li&gt;The word &lt;strong&gt;auspicious&lt;/strong&gt; means&amp;nbsp;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;conducive to success; favourable. &lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;&quot;&gt;(&lt;/span&gt;शुभ,&amp;nbsp;&lt;span style=&quot;&quot;&gt;अनुकूल)&lt;/span&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;​&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;&quot;&gt;Synonyms - Favourable, promising, propitious, bright.&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;&quot;&gt;Antonyms - Unpromising, unfavourable, adverse&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;​&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;&quot;&gt;The word &lt;strong&gt;ominous &lt;/strong&gt;means&amp;nbsp;&lt;strong&gt;giving the worrying impression that something bad is going to happen.&lt;/strong&gt; (अशुभ)&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;Hence &lt;strong&gt;ominous is opposite to the meaning of auspicious.&amp;nbsp;&lt;/strong&gt;&lt;/span&gt;&lt;br /&gt;
	&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

